const BREVO_KEY = '[REDACTED_BREVO_KEY]';

const event = $input.first().json;

// V&eacute;rifier que c'est bien invoice.upcoming
if (event.type !== 'invoice.upcoming') {
  return [];
}

const invoice = event.data?.object || event;
const email = invoice.customer_email || '';

if (!email) {
  return [{ json: { skip: true, reason: 'no email' } }];
}

// Envoyer le template #203 (Retention-PreAnnulation) via Brevo
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.brevo.com/v3/smtp/email',
    headers: { 'api-key': BREVO_KEY, 'Content-Type': 'application/json' },
    body: {
      templateId: 203,
      to: [{ email: email }],
      params: {}
    }
  });
} catch(e) {
  return [{ json: { success: false, error: e.message, email } }];
}

return [{ json: { success: true, email, template: 203 } }];
